    CMINI_01: { text: "¡Quiz de pareja! {actor}, tienes 5 segundos: ¿cuál es la comida culposa favorita de {target}? {target} juzga. Respuesta incorrecta cuesta un sorbo.", enHash: 3453994825 },
    CMINI_02: { text: "¡Dos verdades y una mentira! {actor} — tres cosas de tu vida antes de que se conocieran. {target} tiene un intento para encontrar la mentira. Si la descubre, tú tomas un sorbo.", enHash: 247968167 },
    CMINI_03: { text: "¡Concurso de miradas! Quien se ría primero o aparte la vista responde una pregunta del ganador — honestidad total, sin pasar.", enHash: 270247381 },
    CMINI_04: { text: "¡Hora de imitar! {actor}, haz tu mejor imitación de {target} en una situación específica que tú elijas. {target} lo califica del 1 al 5 — menos de 3 significa que lo intentas de nuevo.", enHash: 999037869 },
    CMINI_05: { text: "¡Piedra, papel o tijera, al mejor de tres! Quien pierda le debe un favor a quien gane esta noche — el ganador lo declara ahora, Lyra no olvida.", enHash: 3885294384 },
    CMINI_06: { text: "¡Guerra de pulgares! El ganador le asigna al perdedor un reto de 10 segundos, ahora mismo. Que valga la pena.", enHash: 3194921702 },
    CMINI_07: { text: "¡Baile espejo! {actor} lidera 15 segundos, {target} imita cada movimiento. Luego cambian. El peor espejo — votan los dos — toma un trago.", enHash: 3722335728 },
    CMINI_08: { text: "¡Adivina mi respuesta! {actor}, pregúntale a {target}: «¿Cuál dirías que es mi cualidad más atractiva?» {target} responde por ti. Luego revela tu respuesta real.", enHash: 2980433586 },
    CMINI_09: { text: "¡Completa la frase! {actor} empieza tres frases sobre {target}: «{target} siempre...», «{target} en secreto...», «{target} nunca...». {target} confirma o corrige cada una.", enHash: 3369604352 },
    CMINI_10: { text: "¡Ronda rápida! 5 segundos cada uno, de ida y vuelta: digan cosas que aman del otro. El primero en dudar, repetir o reírse toma un trago.", enHash: 2339704007 },
    CMINI_11: { text: "¡Duelo de miradas! Un minuto completo, caras cerca, sin hablar, sin reír. Quien rompa primero — quien gane le susurra una instrucción al oído, a cumplirse antes del siguiente nivel.", enHash: 616964384 },
    CMINI_12: { text: "Piedra, papel o tijera — con apuesta. Quien gane elige exactamente dónde quien pierda le da un beso. Tómate tu tiempo para decidir.", enHash: 1656019025 },
    CMINI_13: { text: "¡Caminata a ciegas! {target} cierra los ojos. {actor} le guía por la habitación solo con la punta de los dedos y susurros, luego le conduce a un lugar inesperado. Sin mirar.", enHash: 2900278135 },
    CMINI_14: { text: "Baile congelado — versión lenta. Bailen cerca. Cuando cualquiera de los dos diga 'freeze', quédense completamente quietos, exactamente donde están, durante diez respiraciones. Luego sigan bailando. Tres congeladas cada uno.", enHash: 3431999554 },
    CPE0001: { text: "¿Qué hace {target} en casa pensando que es completamente privado — pero tú ya lo has visto mil veces y nunca has dicho nada?", enHash: 2385319598 },
    CPE0002: { text: "¿Cuál es el hábito más desesperante de {target} que llevas aguantando en silencio desde el principio — y cuánto tiempo llevas con eso guardado?", enHash: 4242779757 },
    CPE0003: { text: "¿Qué cosa de {target} llevas años queriendo tirar a la basura pero nunca has dicho ni pío?", enHash: 3569495104 },
